Here's an example of how you can write unit tests for the `zip_dicts` function using pytest:

```python
import pytest

def test_zip_dicts_happy_path():
    dict1 = {'a': 1, 'b': 2}
    dict2 = {'b': 3, 'c': 4}
    dict3 = {'c': 5, 'd': 6}

    expected_result = {
        'a': [1, None, None],
        'b': [2, 3, None],
        'c': [None, 4, 5],
        'd': [None, None, 6]
    }

    assert zip_dicts(dict1, dict2, dict3) == expected_result

def test_zip_dicts_empty_dicts():
    dict1 = {}
    dict2 = {}
    dict3 = {}

    expected_result = {}

    assert zip_dicts(dict1, dict2, dict3) == expected_result

def test_zip_dicts_no_common_keys():
    dict1 = {'a': 1, 'b': 2}
    dict2 = {'c': 3, 'd': 4}
    dict3 = {'e': 5, 'f': 6}

    expected_result = {
        'a': [1, None, None],
        'b': [2, None, None],
        'c': [None, 3, None],
        'd': [None, 4, None],
        'e': [None, None, 5],
        'f': [None, None, 6]
    }

    assert zip_dicts(dict1, dict2, dict3) == expected_result

def test_zip_dicts_no_common_keys_empty_dicts():
    dict1 = {'a': 1, 'b': 2}
    dict2 = {}
    dict3 = {}

    expected_result = {
        'a': [1, None, None],
        'b': [2, None, None]
    }

    assert zip_dicts(dict1, dict2, dict3) == expected_result

def test_zip_dicts_empty_dicts_empty():
    dict1 = {}
    dict2 = {}
    dict3 = {}

    expected_result = {}

    assert zip_dicts(dict1, dict2, dict3) == expected_result

def test_zip_dicts_none_dict():
    dict1 = {'a': 1, 'b': 2}
    dict2 = None
    dict3 = {'c': 3, 'd': 4}

    with pytest.raises(TypeError):
        zip_dicts(dict1, dict2, dict3)

def test_zip_dicts_none_dict_empty():
    dict1 = {'a': 1, 'b': 2}
    dict2 = None
    dict3 = {}

    expected_result = {
        'a': [1, None, None],
        'b': [2, None, None]
    }

    assert zip_dicts(dict1, dict2, dict3) == expected_result

def test_zip_dicts_none_dict_none():
    dict1 = {'a': 1, 'b': 2}
    dict2 = None
    dict3 = None

    expected_result = {}

    assert zip_dicts(dict1, dict2, dict3) == expected_result
```

These tests cover the following scenarios:

* Happy path: Test that the function works correctly when all input dictionaries have common keys.
* Edge cases: Test that the function handles empty dictionaries and dictionaries with no common keys.
* Error cases: Test that the function raises a `TypeError` when one of the input dictionaries is `None`.
